import { ReactNode, useState, useMemo } from 'react';
import type { Key, Selection, SortDescriptor } from 'react-aria-components';
import { Table, TableCard } from '../../molecules/Table/base';
import { Dropdown } from '@/components/atoms/Dropdown/base';
import { Checkbox } from '@/vendor/untitled-ui/base/checkbox/checkbox';
import { Button } from '@/components/atoms/Button/BaseButton';
import { Settings01 } from '@untitledui/icons';

/**
 * Column configuration for a single column
 */
export interface DataTableColumnConfig<T> {
  /**
   * Column header title
   */
  title: string;

  /**
   * Custom render function for the column cell
   * @param row - The entire row data object
   * @param index - The row index
   */
  render?: (row: T, index: number) => ReactNode;

  /**
   * Whether the column is sortable
   * @default false
   */
  sortable?: boolean;

  /**
   * Tooltip to show on column header
   */
  tooltip?: string;

  /**
   * Custom className for column cells
   */
  className?: string;

  /**
   * Width of the column (CSS value)
   */
  width?: string;

  /**
   * Minimum width of the column (CSS value)
   */
  minWidth?: string;

  /**
   * Whether column is hidden
   * @default false
   */
  hidden?: boolean;
}

/**
 * Column definitions as an object with column keys
 */
export type DataTableColumns<T> = Record<string, DataTableColumnConfig<T>>;

export interface DataTableProps<T extends { id?: Key }> {
  /**
   * Column definitions as an object where keys are column identifiers
   */
  columns: DataTableColumns<T>;

  /**
   * Array of data rows. Each row must have an `id` property.
   */
  data: T[];

  /**
   * Table size variant
   * @default 'sm'
   */
  size?: 'sm' | 'md';

  /**
   * Selection mode
   * @default 'none'
   */
  selectionMode?: 'none' | 'single' | 'multiple';

  /**
   * Selection behavior
   * @default 'toggle'
   */
  selectionBehavior?: 'toggle' | 'replace';

  /**
   * Currently selected keys
   */
  selectedKeys?: Selection;

  /**
   * Callback when selection changes
   */
  onSelectionChange?: (keys: Selection) => void;

  /**
   * Current sort descriptor
   */
  sortDescriptor?: SortDescriptor;

  /**
   * Callback when sort changes
   */
  onSortChange?: (descriptor: SortDescriptor) => void;

  /**
   * Whether to show borders between rows
   * @default true
   */
  bordered?: boolean;

  /**
   * Whether to highlight selected rows
   * @default true
   */
  highlightSelectedRow?: boolean;

  /**
   * Loading state
   */
  loading?: boolean;

  /**
   * Empty state component to show when no data
   */
  emptyState?: ReactNode;

  /**
   * Loading component to show during loading
   */
  loadingComponent?: ReactNode;

  /**
   * ARIA label for the table
   */
  'aria-label'?: string;

  /**
   * Additional className for the table
   */
  className?: string;

  /**
   * Custom row renderer (for advanced use cases)
   */
  renderRow?: (row: T, index: number, columnKeys: string[]) => ReactNode;

  /**
   * Callback when a row is clicked
   */
  onRowClick?: (row: T, index: number) => void;

  /**
   * Default sortable value for columns that don't specify it
   * @default false
   */
  defaultSortable?: boolean;

  /**
   * Show column visibility manager button
   * @default false
   */
  showColumnsVisibilityManager?: boolean;

  /**
   * Callback when column visibility changes
   */
  onColumnVisibilityChange?: (visibleColumns: string[]) => void;
}

/**
 * DataTable component - A declarative wrapper around the UntitledUI Table component
 *
 * Provides a simpler API for rendering tables with column definitions and data arrays.
 * Supports sorting, selection, custom cell renderers, and more.
 *
 * @example
 * // Basic usage
 * interface User {
 *   id: number;
 *   name: string;
 *   email: string;
 * }
 *
 * const columns = {
 *   name: { title: 'Name' },
 *   email: { title: 'Email' },
 * };
 *
 * <DataTable columns={columns} data={users} />
 *
 * @example
 * // With custom renderer (e.g., for actions column)
 * const columns = {
 *   name: { title: 'Name' },
 *   status: {
 *     title: 'Status',
 *     render: (row) => <Badge>{row.status}</Badge>
 *   },
 *   actions: {
 *     title: '',
 *     render: (row) => <Button onClick={() => edit(row)}>Edit</Button>
 *   }
 * };
 *
 * @example
 * // With sorting
 * const [sortDescriptor, setSortDescriptor] = useState<SortDescriptor>({
 *   column: 'name',
 *   direction: 'ascending'
 * });
 *
 * <DataTable
 *   columns={columns}
 *   data={users}
 *   sortDescriptor={sortDescriptor}
 *   onSortChange={setSortDescriptor}
 * />
 */
export function DataTable<T extends { id?: Key }>({
  columns,
  data,
  size = 'sm',
  selectionMode = 'none',
  selectionBehavior = 'toggle',
  selectedKeys,
  onSelectionChange,
  sortDescriptor,
  onSortChange,
  bordered = true,
  highlightSelectedRow = true,
  loading = false,
  emptyState,
  loadingComponent,
  'aria-label': ariaLabel,
  className,
  renderRow,
  onRowClick,
  defaultSortable = false,
  showColumnsVisibilityManager = false,
  onColumnVisibilityChange,
}: DataTableProps<T>) {
  // Get all column keys
  const allColumnKeys = Object.keys(columns);

  // Initialize hidden columns state based on column config
  const initialHiddenColumns = useMemo(
    () => allColumnKeys.filter((key) => columns[key].hidden),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [],
  );

  const [hiddenColumns, setHiddenColumns] = useState<Set<string>>(
    new Set(initialHiddenColumns),
  );

  // Convert columns object to entries and filter out hidden columns
  const columnEntries = useMemo(() => {
    return Object.entries(columns).filter(([key]) => !hiddenColumns.has(key));
  }, [columns, hiddenColumns]);

  const columnKeys = columnEntries.map(([key]) => key);

  // Get value from row using column key
  const getCellValue = (row: T, columnKey: string): unknown => {
    const key = columnKey as keyof T;
    return row[key];
  };

  // Handle column visibility toggle
  const handleColumnVisibilityToggle = (columnKey: string) => {
    setHiddenColumns((prev) => {
      const newHidden = new Set(prev);
      if (newHidden.has(columnKey)) {
        newHidden.delete(columnKey);
      } else {
        newHidden.add(columnKey);
      }

      // Notify parent of visibility change
      const visibleColumns = allColumnKeys.filter((key) => !newHidden.has(key));
      onColumnVisibilityChange?.(visibleColumns);

      return newHidden;
    });
  };

  // Render empty state
  if (!loading && data.length === 0) {
    return (
      emptyState || (
        <div className="flex items-center justify-center py-12 text-sm text-tertiary">
          No data available
        </div>
      )
    );
  }

  // Render loading state
  if (loading) {
    return (
      loadingComponent || (
        <div className="flex items-center justify-center py-12 text-sm text-tertiary">
          Loading...
        </div>
      )
    );
  }

  return (
    <TableCard.Root
      size={size}
      className="relative"
    >
      {showColumnsVisibilityManager && (
        <div className="absolute right-2 top-2 z-50">
          <Dropdown.Root>
            <Button
              size="sm"
              color="tertiary"
              aria-label="Manage column visibility"
            >
              <Settings01 className="size-4" />
            </Button>

            <Dropdown.Popover className="w-56">
              <Dropdown.Menu
                selectionMode="none"
                onAction={() => {}}
              >
                <Dropdown.Section>
                  <Dropdown.SectionHeader className="px-3 py-2 text-sm font-semibold text-primary border-b border-secondary">
                    Show columns
                  </Dropdown.SectionHeader>
                  {allColumnKeys.map((columnKey) => {
                    const columnConfig = columns[columnKey];
                    const isVisible = !hiddenColumns.has(columnKey);

                    return (
                      <Dropdown.Item
                        data-id={`column-toggle-${columnKey}`}
                        key={columnKey}
                        textValue={columnConfig.title}
                        onAction={() => handleColumnVisibilityToggle(columnKey)}
                      >
                        <div className="flex items-center gap-2 w-full">
                          <Checkbox
                            isSelected={isVisible}
                            onChange={() => {}}
                            aria-label={`Toggle ${columnConfig.title}`}
                          />
                          <span className="flex-1 text-left">
                            {columnConfig.title}
                          </span>
                        </div>
                      </Dropdown.Item>
                    );
                  })}
                </Dropdown.Section>
              </Dropdown.Menu>
            </Dropdown.Popover>
          </Dropdown.Root>
        </div>
      )}

      <Table
        aria-label={ariaLabel || 'Data table'}
        size={size}
        selectionMode={selectionMode}
        selectionBehavior={selectionBehavior}
        selectedKeys={selectedKeys}
        onSelectionChange={onSelectionChange}
        sortDescriptor={sortDescriptor}
        onSortChange={onSortChange}
        className={className}
      >
        <Table.Header bordered={bordered}>
          {columnEntries.map(([columnKey, columnConfig], index) => {
            // Apply defaultSortable if sortable is not explicitly set
            const isSortable =
              columnConfig.sortable !== undefined
                ? columnConfig.sortable
                : defaultSortable;

            return (
              <Table.Head
                key={columnKey}
                id={columnKey}
                label={columnConfig.title}
                tooltip={columnConfig.tooltip}
                isRowHeader={index === 0}
                allowsSorting={isSortable}
                style={{
                  width: columnConfig.width,
                  minWidth: columnConfig.minWidth,
                }}
              />
            );
          })}
        </Table.Header>

        <Table.Body>
          {data.map((row, rowIndex) => {
            const rowId = row.id ?? rowIndex;

            // Use custom row renderer if provided
            if (renderRow) {
              return (
                <Table.Row
                  key={rowId}
                  id={rowId}
                  highlightSelectedRow={highlightSelectedRow}
                  onAction={
                    onRowClick ? () => onRowClick(row, rowIndex) : undefined
                  }
                >
                  {renderRow(row, rowIndex, columnKeys)}
                </Table.Row>
              );
            }

            // Default row rendering
            return (
              <Table.Row
                key={rowId}
                id={rowId}
                highlightSelectedRow={highlightSelectedRow}
                onAction={
                  onRowClick ? () => onRowClick(row, rowIndex) : undefined
                }
              >
                {columnEntries.map(([columnKey, columnConfig]) => {
                  const cellValue = getCellValue(row, columnKey);
                  const cellContent = columnConfig.render
                    ? columnConfig.render(row, rowIndex)
                    : cellValue;

                  return (
                    <Table.Cell
                      key={columnKey}
                      className={columnConfig.className}
                    >
                      {cellContent as ReactNode}
                    </Table.Cell>
                  );
                })}
              </Table.Row>
            );
          })}
        </Table.Body>
      </Table>
    </TableCard.Root>
  );
}

DataTable.displayName = 'DataTable';

export default DataTable;
